; Passenger class refers to the social status of the passengers (1 = 1st, 2 = 2nd, 3 = 3rd); 
; The survival rate is calculated as the number of survivors divided by the total number of passengers; 
; Ports of embarkation are located in different countries, and each port has a unique identifier.

sql:
SELECT SUM(survived) AS total_first_class_survivors
FROM passengers
WHERE pclass = 1 AND survived = 1;

SELECT IFNULL(cabin_description, 'No Description Available') AS cabin_info
FROM cabin_details
WHERE cabin_type = 'double';
